'use client'

import { useState } from 'react'
import { Button } from '@/components/ui/button'
import Link from 'next/link'
import { Activity, Edit, PlayCircle, Trash2, Eye } from 'lucide-react'
import { deletePost, togglePublished } from '@/app/blog/admin/actions'

export function AdminPostActions({ id, slug, published }: { id: string, slug: string, published: boolean }) {
  const [loading, setLoading] = useState(false)

  const handleToggle = async () => {
    setLoading(true)
    try {
      await togglePublished(id, !published)
    } finally {
      setLoading(false)
    }
  }

  const handleDelete = async () => {
    if (!confirm('Are you sure you want to delete this post? This cannot be undone.')) return
    
    setLoading(true)
    try {
      await deletePost(id)
    } finally {
      // Re-enable if navigation doesn't instantly tear down the component
      setLoading(false)
    }
  }

  return (
    <div className="flex items-center justify-end gap-1">
      <Link href={`/blog/${slug}`} target="_blank">
        <Button 
          variant="ghost" 
          size="icon" 
          className="h-8 w-8 text-muted-foreground hover:text-primary"
          title="Preview Post"
        >
          <Eye className="h-4 w-4" />
        </Button>
      </Link>
      <Button
        variant="ghost"
        size="sm"
        className="h-8 px-2 text-muted-foreground hover:text-foreground"
        onClick={handleToggle}
        disabled={loading}
      >
        {published ? 'Unpublish' : 'Publish'}
      </Button>
      
      <Link href={`/blog/admin/${id}/edit`}>
        <Button 
          variant="ghost" 
          size="icon" 
          className="h-8 w-8 text-muted-foreground hover:text-blue-600 dark:hover:text-blue-400"
          disabled={loading}
        >
          <Edit className="h-4 w-4" />
        </Button>
      </Link>
      
      <Button
        variant="ghost"
        size="icon"
        className="h-8 w-8 text-muted-foreground hover:text-destructive dark:hover:text-red-400"
        onClick={handleDelete}
        disabled={loading}
      >
        <Trash2 className="h-4 w-4" />
      </Button>
    </div>
  )
}

'use client'

import { useCreateBlockNote } from '@blocknote/react'
import { BlockNoteView } from '@blocknote/mantine'
import '@blocknote/mantine/style.css'
import { uploadBlogImageAction } from '@/app/blog/admin/actions'
import { PartialBlock } from '@blocknote/core'
import { useTheme } from 'next-themes'
import { useEffect, useState } from 'react'

interface BlockNoteEditorProps {
    initialContent?: PartialBlock[] | any
    onChange: (content: any) => void
}

function InnerEditor({ initialContent, onChange, resolvedTheme }: { initialContent: any, onChange: any, resolvedTheme: any }) {
    const editor = useCreateBlockNote({
        uploadFile: async (file: File) => {
            const formData = new FormData()
            formData.append('file', file)
            return uploadBlogImageAction(formData)
        },
        initialContent: Array.isArray(initialContent) && initialContent.length > 0 ? initialContent : undefined,
    })

    return (
        <BlockNoteView
            editor={editor}
            theme={resolvedTheme === 'dark' ? 'dark' : 'light'}
            onChange={() => {
                onChange(editor.document)
            }}
        />
    )
}

export function BlockNoteEditor({ initialContent, onChange }: BlockNoteEditorProps) {
    const { resolvedTheme } = useTheme()
    const [mounted, setMounted] = useState(false)

    // Avoid hydration mismatch for theme
    useEffect(() => {
        setMounted(true)
    }, [])

    if (!mounted) {
        return (
            <div className="min-h-[300px] w-full animate-pulse rounded-md border border-border bg-muted/50" />
        )
    }

    return (
        <div className="min-h-[300px] w-full rounded-md border border-border bg-card py-4">
            <InnerEditor initialContent={initialContent} onChange={onChange} resolvedTheme={resolvedTheme} />
        </div>
    )
}

'use client'

import { useCreateBlockNote } from '@blocknote/react'
import { BlockNoteView } from '@blocknote/mantine'
import '@blocknote/mantine/style.css'
import { PartialBlock } from '@blocknote/core'
import { useTheme } from 'next-themes'
import { useEffect, useState } from 'react'

interface BlockNoteRendererProps {
  content: PartialBlock[] | any
}

function InnerRenderer({ content, resolvedTheme }: { content: any, resolvedTheme: any }) {
  const editor = useCreateBlockNote({
    initialContent: Array.isArray(content) && content.length > 0 ? content : undefined,
  })

  return (
    <BlockNoteView
      editor={editor}
      editable={false}
      theme={resolvedTheme === 'dark' ? 'dark' : 'light'}
    />
  )
}

export function BlockNoteRenderer({ content }: BlockNoteRendererProps) {
  const { resolvedTheme } = useTheme()
  const [mounted, setMounted] = useState(false)

  useEffect(() => {
    setMounted(true)
  }, [])

  if (!mounted) return null

  return (
    <div className="blocknote-reader w-full bg-transparent">
      <InnerRenderer content={content} resolvedTheme={resolvedTheme} />
    </div>
  )
}

import { ArrowRight, ChevronRight } from 'lucide-react'
import React from 'react'

interface RenderInlineProps {
  content: any[]
}

const RenderInline = ({ content }: RenderInlineProps) => {
  if (!content || !Array.isArray(content)) return null

  return (
    <>
      {content.map((inline, index) => {
        if (inline.type === 'text' || inline.type === 'link') {
          let el = <>{inline.text}</>

          if (inline.styles) {
            const bgColor = inline.styles.backgroundColor
            const textColor = inline.styles.textColor

            if (bgColor && bgColor !== 'default') {
              el = <span style={{ backgroundColor: bgColor }}>{el}</span>
            }
            if (textColor && textColor !== 'default') {
              el = <span style={{ color: textColor }}>{el}</span>
            }

            if (inline.styles.bold) el = <strong>{el}</strong>
            if (inline.styles.italic) el = <em>{el}</em>
            if (inline.styles.underline) el = <u>{el}</u>
            if (inline.styles.strike) el = <del>{el}</del>
            if (inline.styles.code) el = <code className="rounded bg-muted px-1.5 py-0.5 font-mono text-sm">{el}</code>
          }

          if (inline.type === 'link' && inline.href) {
            el = (
              <a href={inline.href} target="_blank" rel="noopener noreferrer" className="font-medium text-primary hover:underline">
                {el}
              </a>
            )
          }

          return <React.Fragment key={index}>{el}</React.Fragment>
        }
        return null
      })}
    </>
  )
}

interface CustomRendererProps {
  blocks: any[]
}

export function CustomRenderer({ blocks }: CustomRendererProps) {
  if (!blocks || !Array.isArray(blocks)) return null

  // Pre-process blocks to group consecutive list items together
  const groupedBlocks: any[] = []
  let currentGroup: { type: 'ul' | 'ol' | 'checkList', items: any[] } | null = null

  blocks.forEach(block => {
    if (block.type === 'bulletListItem') {
      if (currentGroup?.type === 'ul') {
        currentGroup.items.push(block)
      } else {
        if (currentGroup) groupedBlocks.push(currentGroup)
        currentGroup = { type: 'ul', items: [block] }
      }
    } else if (block.type === 'numberedListItem') {
      if (currentGroup?.type === 'ol') {
        currentGroup.items.push(block)
      } else {
        if (currentGroup) groupedBlocks.push(currentGroup)
        currentGroup = { type: 'ol', items: [block] }
      }
    } else if (block.type === 'checkListItem') {
      if (currentGroup?.type === 'checkList') {
        currentGroup.items.push(block)
      } else {
        if (currentGroup) groupedBlocks.push(currentGroup)
        currentGroup = { type: 'checkList', items: [block] }
      }
    } else {
      if (currentGroup) {
        groupedBlocks.push(currentGroup)
        currentGroup = null
      }
      groupedBlocks.push(block)
    }
  })
  if (currentGroup) groupedBlocks.push(currentGroup)

  return (
    <>
      {groupedBlocks.map((groupOrBlock, index) => {
        if (groupOrBlock.type === 'ul') {
          return (
            <ul className="list-disc list-outside ml-6 my-4 space-y-2" key={`ul-${index}`}>
              {groupOrBlock.items.map((item: any) => (
                <li key={item.id}>
                  <RenderInline content={item.content} />
                  {item.children && item.children.length > 0 && <CustomRenderer blocks={item.children} />}
                </li>
              ))}
            </ul>
          )
        }
        if (groupOrBlock.type === 'ol') {
          return (
            <ol className="list-decimal list-outside ml-6 my-4 space-y-2" key={`ol-${index}`}>
              {groupOrBlock.items.map((item: any) => (
                <li key={item.id}>
                  <RenderInline content={item.content} />
                  {item.children && item.children.length > 0 && <CustomRenderer blocks={item.children} />}
                </li>
              ))}
            </ol>
          )
        }
        if (groupOrBlock.type === 'checkList') {
          return (
            <div className="flex flex-col space-y-2 my-4" key={`checklist-${index}`}>
              {groupOrBlock.items.map((item: any) => (
                <div key={item.id} className="flex flex-row items-start gap-3">
                  <input
                    type="checkbox"
                    checked={item.props?.checked === true}
                    readOnly
                    className="mt-1 h-4 w-4 shrink-0 rounded border-gray-300 text-primary focus:ring-primary"
                  />
                  <div className={`flex-1 ${item.props?.checked === true ? 'line-through' : ''}`}>
                    <RenderInline content={item.content} />
                    {item.children && item.children.length > 0 && <CustomRenderer blocks={item.children} />}
                  </div>
                </div>
              ))}
            </div>
          )
        }

        const block = groupOrBlock
        const { id, type, props, content, children } = block
        const renderChildren = children && children.length > 0 ? <CustomRenderer blocks={children} /> : null

        switch (type) {
          case 'paragraph':
            return (
              <p key={id}>
                {content && content.length > 0 ? <RenderInline content={content} /> : <br />}
                {renderChildren}
              </p>
            )
          case 'quote':
          case 'blockQuote':
            return (
              <blockquote key={id} className="border-l-4 border-primary/50 bg-muted/30 px-6 py-4 my-6 text-foreground italic rounded-r-lg">
                <RenderInline content={content} />
                {renderChildren}
              </blockquote>
            )
          case 'heading': {
            const level = typeof props?.level === 'number' ? Math.min(Math.max(props.level, 1), 6) : 1
            let className = ''
            if (level === 1) className = 'text-4xl mt-8 mb-5 font-bold'
            if (level === 2) className = 'text-3xl mt-6 mb-4 font-bold'
            if (level === 3) className = 'text-2xl mt-5 mb-3 font-bold'
            const HeadingTag = `h${level}` as 'h1' | 'h2' | 'h3'
            return (
              <HeadingTag className={className} key={id}>
                <RenderInline content={content} />
                {renderChildren}
              </HeadingTag>
            )
          }
          case 'toggle':
          case 'toggleListItem':
            return (
              <details key={id} className="my-4 group">
                <summary className="cursor-pointer font-medium list-none flex items-start gap-2 [&::-webkit-details-marker]:hidden">
                  <span className="transition-transform group-open:rotate-90 text-muted-foreground text-xs mt-1.5"><ChevronRight className='h-4 w-4' /></span>
                  <div className="flex-1">
                    <RenderInline content={content} />
                  </div>
                </summary>
                <div className="pl-6 mt-2 space-y-2">
                  {renderChildren}
                </div>
              </details>
            )
          case 'image': {
            const align = props?.textAlignment || 'center'
            const alignClass = align === 'left' ? 'items-start' : align === 'right' ? 'items-end' : 'items-center'
            const widthObj = props?.previewWidth ? { width: `${props.previewWidth}px`, maxWidth: '100%' } : { width: '100%' }

            return (
              <figure key={id} className={`flex flex-col my-5 ${alignClass}`}>
                <div style={widthObj} className="relative flex flex-col">
                  <img
                    src={props?.url}
                    alt={props?.caption || props?.alt || ''}
                    className="overflow-hidden object-cover w-full"
                  />
                  {(props?.caption || props?.alt) && (
                    <figcaption className="bg-secondary/50 mt-2 p-2 text-center text-sm text-muted-foreground rounded-lg w-full">
                      {props.caption || props.alt}
                    </figcaption>
                  )}
                </div>
                {renderChildren}
              </figure>
            )
          }
          default:
            return (
              <div key={id}>
                {content && <RenderInline content={content} />}
                {renderChildren}
              </div>
            )
        }
      })}
    </>
  )
}
